        color: #e0e0e0 !important;
    }

    /* Miron Challenge: Academic Look */
    .miron-portal-container {
        width: calc(100% - 40px);
        max-width: 700px;
        margin: 3em auto;
        font-family: 'Poppins', sans-serif;
        font-size: ${baseFontSize}px; 
        position: relative;
        z-index: 100;
        box-sizing: border-box;
    }

    .miron-question-card {
        background: #121212;
        border: 1px solid rgba(255, 255, 255, 0.08);
        border-radius: 20px;
        padding: 1.5em;
        box-shadow: 0 15px 40px rgba(0,0,0,0.4);
        color: #fff;
        display: none; /* Hidden for carousel logic */
    }

    .miron-question-card.active {
        display: flex;
        flex-direction: column;
        animation: qFadeIn 0.4s ease-out;
    }

    @keyframes qFadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

    .q-header {
        display: flex;
        align-items: center;
        margin-bottom: 1.2em;
        gap: 0.8em;
    }

    .miron-orb-mini {
        width: 10px; height: 10px;
        background: #42d7b8;
        border-radius: 50%;
        box-shadow: 0 0 10px #42d7b8;
    }

    .q-label {
        color: #42d7b8;
        font-weight: 700;
        font-size: 0.75em; 
        text-transform: uppercase;
        letter-spacing: 1.5px;
    }

    .q-points-badge {
        margin-left: auto;
        font-size: 0.7em;
        background: rgba(255, 255, 255, 0.05);
        padding: 4px 10px;
        border-radius: 6px;
        color: #888;
    }

    .q-text {
        font-size: 1.15em; 
        line-height: 1.4;
        margin-bottom: 1.2em;
        font-weight: 500;
    }

    /* ADAPTIVE GRID: 2 per row if possible */
    .q-options {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
        gap: 10px;
    }

    .q-opt-btn {
        background: rgba(255, 255, 255, 0.03);
        border: 1px solid rgba(255, 255, 255, 0.1);
        padding: 12px 16px;
        border-radius: 12px;
        color: #ccc;
        font-size: 0.9em;
        font-family: inherit;
        text-align: left;
        cursor: pointer;
        transition: all 0.2s;
        display: flex;
        align-items: center;
        gap: 12px;
    }

    .q-opt-btn::before {
        content: '';
        width: 14px; height: 14px;
        border: 2px solid #555;
        border-radius: 50%;
        flex-shrink: 0;
    }

    .q-opt-btn:hover { background: rgba(255, 255, 255, 0.06); }

    /* Exam Session Active Look */
    .q-opt-btn.selected {
        background: rgba(66, 215, 184, 0.05);
        border-color: #42d7b8;
        color: #fff;
    }
    .q-opt-btn.selected::before {
        border-color: #42d7b8;
        background: #42d7b8;
        box-shadow: 0 0 8px #42d7b8;
    }

    .q-footer-nav {
        margin-top: 1.5em;
        padding-top: 1em;
        border-top: 1px solid rgba(255, 255, 255, 0.05);
        display: flex;
        justify-content: space-between;
        align-items: center;
    }

    .q-nav-btn {
        background: none; border: none;
        color: #666; cursor: pointer;
        font-size: 0.8em; font-weight: 600;
        display: flex; align-items: center; gap: 5px;
    }

    .q-nav-btn:hover { color: #42d7b8; }

    .q-counter {
        font-size: 0.7em; color: #555; font-weight: 700;
    }

    .q-submit {
        background: #42d7b8;
        color: #0c0c0c;
        font-weight: 700;
        padding: 10px 20px;
        border: none;
        border-radius: 10px;
        cursor: pointer;
        font-family: inherit;
    }

    /* Matching Layout */
    .q-matching-container {
        display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 1em;
    }
    .q-match-item {
        padding: 10px; border-radius: 10px; font-size: 0.85em;
        background: rgba(255,255,255,0.03); border: 1px dashed rgba(255,255,255,0.1);
    }
`;

