        parent.querySelectorAll('.q-opt-btn').forEach(btn => btn.style.borderColor = 'rgba(255,255,255,0.1)');
        target.style.borderColor = '#42d7b8';
        target.style.background = 'rgba(66, 215, 184, 0.1)';
    }
    if (target.classList.contains('q-submit')) {
        target.innerText = "Correct! +5 Linkoins";
        target.style.background = "#b1d34b";
        // Future: Call Supabase to increment balance
    }
};

ops.replace_with:
const handleIframeClick = (e) => {
    const target = e.target;
    const doc = iframe.contentDocument;

    // Option Selection
    if (target.classList.contains('q-opt-btn')) {
        const parent = target.closest('.q-options');
        parent.querySelectorAll('.q-opt-btn').forEach(btn => btn.classList.remove('selected'));
        target.classList.add('selected');
    }

    // Submit Button
    if (target.classList.contains('q-submit')) {
        target.innerText = "Verified +5";
        target.style.background = "#b1d34b";
        target.disabled = true;
    }

    // Navigation Logic (Carousel)
    if (target.classList.contains('q-nav-next') || target.classList.contains('q-nav-prev')) {
        const container = target.closest('.miron-portal-container');
        const cards = container.querySelectorAll('.miron-question-card');
        const currentActive = container.querySelector('.miron-question-card.active');
        let currentIndex = Array.from(cards).indexOf(currentActive);

        currentActive.classList.remove('active');

        if (target.classList.contains('q-nav-next')) {
            currentIndex = (currentIndex + 1) % cards.length;
        } else {
            currentIndex = (currentIndex - 1 + cards.length) % cards.length;
        }

        cards[currentIndex].classList.add('active');

        // Update Counter text if exists
        const counter = container.querySelector('.q-counter');
        if (counter) counter.innerText = `QUESTION ${currentIndex + 1} OF ${cards.length}`;
    }
};

