        target.classList.add('q-opt-selected');

        // Show Submit button only after selection
        const submitBtn = card.querySelector('.q-submit');
        if (submitBtn) {
            submitBtn.style.display = 'flex';
        }
    }

    if (target.classList.contains('q-submit')) {
        target.innerText = "Correct! +5 Linkoins";
        target.style.background = "#42d7b8";
        target.style.color = "#0c0c0c";
    }
};

